#include <stdio.h>

int main() {
    int num1, num2, num3;
    scanf("%d %d %d", &num1, &num2, &num3);

    // Check and print the largest number
    if (num1 >= num2 && num1 >= num3) {
        printf("Largest: %d\n", num1);
    } else if (num2 >= num1 && num2 >= num3) {
        printf("Largest: %d\n", num2);
    } else {
        printf("Largest: %d\n", num3);
    }

    return 0;
}

